import React, { useEffect, useState } from "react";
import { Box, Typography, Container, Grid, useMediaQuery } from "@mui/material";

const textOptions = ["React.js", "React Native", "Full Stack Development"];




export default function Intro() {
  const [currentText, setCurrentText] = useState("");
  const [textIndex, setTextIndex] = useState(0);
  const [charIndex, setCharIndex] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);

  useEffect(() => {
    const currentString = textOptions[textIndex];
    const timeout = setTimeout(() => {
      if (isDeleting) {
        setCurrentText(currentString.substring(0, charIndex - 1));
        setCharIndex(charIndex - 1);
      } else {
        setCurrentText(currentString.substring(0, charIndex + 1));
        setCharIndex(charIndex + 1);
      }

      // If we reach the end of the string, start deleting
      if (!isDeleting && charIndex === currentString.length) {
        setIsDeleting(true);
      } 
      // If we are deleting and reach the start, move to the next string
      else if (isDeleting && charIndex === 0) {
        setIsDeleting(false);
        setTextIndex((textIndex + 1) % textOptions.length);
      }
    }, isDeleting ? 50 : 150); // Adjust typing speed here

    return () => clearTimeout(timeout);
  }, [currentText, charIndex, isDeleting, textIndex]);

  // Use media query to determine if the screen is small (mobile view)
  const isMobile = useMediaQuery((theme) => theme.breakpoints.down("md"));

  return (
    <Container maxWidth="xl">
      <section style={styles.hero} id="home">
      <div style={styles.socialLinks}>
        {/* <a href="#" style="social-icon"><i style="fa-brands fa-github"></i></a>
        <a href="#" style="social-icon"><i style="fa-brands fa-discord"></i></a>
        <a href="#" style="social-icon"><i style="fa-brands fa-twitter"></i></a> */}
      </div>

      <div style={styles.heroContent}>
        <div className="hero-text">
          <h1>
            Elias is a <span className="accent">web designer</span> and<br />
            <span className="accent">front-end developer</span>
          </h1>
          <p className="hero-description">
            He crafts responsive websites where technologies<br />
            meet creativity
          </p>
          <button className="btn-primary">Contact me !!</button>
        </div>

        <div className="hero-image">
          <img src="assets/header_img.png" alt="Elias in a hoodie" />
          <div className="status-badge">
            <div className="status-dot"></div>
            <p>Currently working on <span className="bold">Portfolio</span></p>
          </div>
          <div className="geometric-element rect-1">
          <img src="assets/hero_sub.png" alt="Elias in a hoodie" />
          </div>
          <div className="geometric-element dot-pattern-1">
          <img src="assets/Dots.png" alt="Elias in a hoodie" />
          </div>
        </div>
      </div>
    </section>
    </Container>
  );
}


